    ops = ['TweetCounts']
    args = [[]]
    for _ in range(max(1, size)):
        name = rng.choice(names)
        if rng.random() < 0.7:
            ops.append('recordTweet')
            args.append([name, rng.randint(0, 5000)])
        else:
            freq = rng.choice(['minute', 'hour', 'day'])
            start = rng.randint(0, 2000)
            end = start + rng.randint(0, 3000)
            ops.append('getTweetCountsPerFrequency')
            args.append([freq, name, start, end])
