class TweetCounts:
    def __init__(self):
        self.records = {}

    def recordTweet(self, tweetName, time):
        self.records.setdefault(tweetName, []).append(time)

    def getTweetCountsPerFrequency(self, freq, tweetName, startTime, endTime):
        width = 60 if freq == 'minute' else 3600 if freq == 'hour' else 86400
        n_chunks = (endTime - startTime) // width + 1
        counts = [0] * n_chunks
        for t in self.records.get(tweetName, []):
            if startTime <= t <= endTime:
                counts[(t - startTime) // width] += 1
        return counts

