class TweetCounts {
    constructor() {
        this.records = new Map();
    }
    recordTweet(tweetName, time) {
        if (!this.records.has(tweetName)) this.records.set(tweetName, []);
        this.records.get(tweetName).push(time);
    }
    getTweetCountsPerFrequency(freq, tweetName, startTime, endTime) {
        const width = freq === 'minute' ? 60 : freq === 'hour' ? 3600 : 86400;
        const nChunks = Math.floor((endTime - startTime) / width) + 1;
        const counts = new Array(nChunks).fill(0);
        const times = this.records.get(tweetName) || [];
        for (const t of times) {
            if (t >= startTime && t <= endTime) {
                counts[Math.floor((t - startTime) / width)] += 1;
            }
        }
        return counts;
    }
}
